import okhttp3.Interceptor
import okhttp3.OkHttpClient
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory

object NetworkModule {
    private const val BASE_URL_DEV = "https://api.example.com/dev/users/"
    private const val BASE_URL_STAGING = "https://api.example.com/staging/users/"
    private const val BASE_URL_PROD = "https://api.example.com/prod/users/"

    fun createRetrofitInstance(environment: String, authToken: String): Retrofit {
        val client = OkHttpClient.Builder()
            .addInterceptor { chain ->
                val originalRequest = chain.request()
                val newRequest = originalRequest.newBuilder()
                    .header("Authorization", "Bearer $authToken")
                    .build()
                chain.proceed(newRequest)
            }
            .build()

        return Retrofit.Builder()
            .baseUrl(getBaseUrl(environment))
            .addConverterFactory(GsonConverterFactory.create())
            .client(client)
            .build()
    }

    private fun getBaseUrl(environment: String): String {
        return when (environment) {
            "dev" -> BASE_URL_DEV
            "staging" -> BASE_URL_STAGING
            "prod" -> BASE_URL_PROD
            else -> throw IllegalArgumentException("Invalid environment")
        }
    }
}